-- School SMS workflow-aligned seed data (MySQL 8)
-- Applies to schema generated by EF migration scripts in Data/Migrations.
-- Active school year is 2026-2027.
-- All seeded students are intentionally unenrolled but remain connected to users,
-- preferred grade levels, curriculum, and requirement workflows.

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- Reset transactional and workflow data
TRUNCATE TABLE audit_logs;
TRUNCATE TABLE enrollment_state_transitions;
TRUNCATE TABLE governed_operation_logs;
TRUNCATE TABLE exception_queue_items;
TRUNCATE TABLE archive_records;
