TRUNCATE TABLE enrollments;
TRUNCATE TABLE class_offerings;
TRUNCATE TABLE curriculum_subjects;
TRUNCATE TABLE sections;
TRUNCATE TABLE students;
TRUNCATE TABLE teachers;
