-- Reset master data used by workflows
TRUNCATE TABLE subjects;
TRUNCATE TABLE curricula;
TRUNCATE TABLE school_settings;
TRUNCATE TABLE grading_periods;
TRUNCATE TABLE grade_components;
TRUNCATE TABLE school_years;
TRUNCATE TABLE grade_levels;
TRUNCATE TABLE rooms;
TRUNCATE TABLE time_slots;

SET FOREIGN_KEY_CHECKS = 1;

