INSERT INTO curriculum_subjects (curriculum_id, grade_level_id, subject_id, semester, is_required, sort_order, created_at, updated_at)
SELECT @cur, s.grade_level_id, s.Id, 1, 1, ROW_NUMBER() OVER (PARTITION BY s.grade_level_id ORDER BY s.code), UTC_TIMESTAMP(6), UTC_TIMESTAMP(6)
FROM subjects s;

INSERT INTO students (
    user_id, lrn, student_number, first_name, last_name, middle_name, birthdate, age, sex,
    address, contact_no, guardian_name, guardian_contact, previous_school,
    preferred_grade_level_id, preferred_curriculum_id, status, created_at, updated_at
)
SELECT
    u.Id,
    CONCAT('LRN-', LPAD(seq.n, 4, '0')),
    CONCAT('STU-', LPAD(1000 + seq.n, 4, '0')),
    names.first_name,
    names.last_name,
    names.middle_name,
    DATE_ADD('2011-06-01', INTERVAL seq.n DAY),
    13 + MOD(seq.n, 4),
    CASE WHEN MOD(seq.n, 2) = 0 THEN 'F' ELSE 'M' END,
    CONCAT('Purok ', seq.n),
    CONCAT('0918', LPAD(seq.n, 7, '0')),
    names.guardian_name,
    CONCAT('0999', LPAD(seq.n, 7, '0')),
    CASE WHEN MOD(seq.n, 6) = 0 THEN CONCAT('Previous School ', LPAD(seq.n, 2, '0')) ELSE NULL END,
    CASE
        WHEN seq.n BETWEEN 1 AND 12 THEN @g7
        WHEN seq.n BETWEEN 13 AND 23 THEN @g8
        WHEN seq.n BETWEEN 24 AND 34 THEN @g9
        ELSE @g10
    END,
    @cur,
    CASE
        WHEN seq.n = 8 THEN 'LOCKED'
        WHEN seq.n = 10 THEN 'INACTIVE'
        ELSE 'ACTIVE'
    END,
    UTC_TIMESTAMP(6),
    UTC_TIMESTAMP(6)
FROM (
    SELECT @rownum_students := @rownum_students + 1 AS n
    FROM information_schema.COLUMNS, (SELECT @rownum_students := 0) init_students
    LIMIT 45
) AS seq
JOIN users u ON u.username = CONCAT('student', LPAD(seq.n, 2, '0'))
JOIN (
    SELECT 1 AS n, 'Alyssa' AS first_name, 'Fernandez' AS last_name, 'Lopez' AS middle_name, 'Marites Fernandez' AS guardian_name
